example.code:
{
  "terms": [
    {
      "term": "mission",
      "definition": "Why we exist beyond profit.",
      "example": "ACME exists to make lending accessible to micro-businesses.",
      "anti_example": "ACME is a bank."
    },
    {
      "term": "vision",
      "definition": "Future-state world we aim to create.",
      "example": "By 2030, every micro-business in the EU can access fair credit in 60s.",
      "anti_example": "Be number one."
    },
    {
      "term": "OKR",
      "definition": "Objective + 3-5 Key Results measurable per cycle.",
      "example": "Objective: pan-EU expansion. KR1: launch 9 countries by Q4.",
      "anti_example": "Do better."
    },
    {
      "term": "SMART",
      "definition": "Specific, Measurable, Achievable, Relevant, Time-bound.",
      "example": "Reduce TTM from 180 to 60 days by 2026-Q4.",
      "anti_example": "Make TTM faster."
    },
    {
      "term": "strategy_vs_tactics",
      "definition": "Strategy = choices about where to play and how to win. Tactics = execution moves.",
      "example": "Strategy: focus on micro-business. Tactic: launch a referral campaign.",
      "anti_example": "Strategy: launch a referral campaign."
    }
  ],
  "last_updated": "2026-05-22"
}
